388: static char *skipelem(char *path, char *name, int max)
389: {
390: 	while (*path == '/') {
391: 		path++;
392: 	}
393: 	if (*path == 0) { return NULL; }
394: 	char *s = path;
395: 	while (*path != '/' && *path != 0) {
396: 		path++;
397: 	}
398: 	int len = path - s;
399: 	if (len > max) {
400: 		len = max;
401: 	}
402: 	name[len] = 0;
403: 	memmove(name, s, len);
404: 	while (*path == '/') {
405: 		path++;
406: 	}
407: 	return path;
408: }
