448: int fdalloc3(struct file *f, int fd, int flag)
449: {
450: 	// if (fd < 0)
451: 	// 	panic("fdalloc3");
452: 
453: 	__debug_info("fdalloc3", "in fd=%d flag=%d\n", fd, flag);
454: 	struct proc *p = myproc();
455: 	struct fdtable *fdt = &p->fds, *prev = NULL;
456: 
457: 	while (fdt && fdt->basefd + NOFILE <= fd) {
458: 		prev = fdt;
459: 		fdt = fdt->next;
460: 	}
461: 	if (!fdt || fdt->basefd > fd) {  // no next table, or next table is not continuous
462: 		struct fdtable *fdnew = newfdtable(fd - fd % NOFILE, fdt);
463: 		if (fdnew == NULL) {
464: 			return -1;
465: 		}
466: 		prev->next = fdnew;
467: 		fdt = fdnew;
468: 		__debug_info("fdalloc3", "alloc %p base=%d\n",
469: 									fdnew, fdnew->basefd);
470: 	}
471: 
472: 	int fd2 = fd % NOFILE;
473: 	if (fdt->arr[fd2] != NULL) {
474: 		fdt->exec_close &= ~(1 << fd2);
475: 		fileclose(fdt->arr[fd2]);
476: 		fdt->arr[fd2] = f;
477: 	} else {
478: 		fdt->arr[fd2] = f;
479: 		fdt->used++;
480: 		if (fd2 == fdt->nextfd) { // unfortunately, we need to update nextfd
481: 			while (++fdt->nextfd < NOFILE) {
482: 				if (fdt->arr[fdt->nextfd] == NULL) {
483: 					break;
484: 				}
485: 			}
486: 		}
487: 	}
488: 	__debug_info("fdalloc3", "table %p base=%d, nextfd=%d, fd2=%d, fd=%d\n",
489: 								fdt, fdt->basefd, fdt->nextfd, fd2, fd);
490: 
491: 	if (flag)
492: 		fdt->exec_close |= (1 << fd2);
493: 
494: 	return fd;
495: }
