184: // Return a locked buf with the contents of the indicated block.
185: struct buf* 
186: bread(uint dev, uint sectorno)
187: {
188: 	struct buf *b;
189: 	b = bget(dev, sectorno);
190: 	if (!b->valid) {
191: 		disk_read(b);
192: 		b->valid = 1;
193: 	}
194: 	return b;
195: }
